"use client";

import { useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";

import { getBriefById } from "@/lib/briefs";
import { storeSessionBootstrap } from "@/lib/session";
import type { PreteachPayload } from "@/lib/types";

type PreteachFlowProps = {
  briefId: string;
};

export function PreteachFlow({ briefId }: PreteachFlowProps) {
  const router = useRouter();
  const brief = useMemo(() => getBriefById(briefId), [briefId]);
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(true);
  const [starting, setStarting] = useState(false);
  const [error, setError] = useState("");
  const [payload, setPayload] = useState<PreteachPayload | null>(null);
  const [selected, setSelected] = useState<string[]>([]);

  useEffect(() => {
    let cancelled = false;
    void (async () => {
      setLoading(true);
      setError("");
      try {
        const response = await fetch("/api/preteach/init", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ briefId }),
        });
        if (!response.ok) {
          throw new Error("Could not load pre-teach content.");
        }
        const nextPayload = (await response.json()) as PreteachPayload;
        if (!cancelled) {
          setPayload(nextPayload);
        }
      } catch (fetchError) {
        if (!cancelled) {
          setError(fetchError instanceof Error ? fetchError.message : "Pre-teach failed.");
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [briefId]);

  const toggleStrategy = (option: string) => {
    setSelected((current) => {
      if (current.includes(option)) {
        return current.filter((entry) => entry !== option);
      }
      if (current.length >= 2) {
        return current;
      }
      return [...current, option];
    });
  };

  const startSession = async () => {
    if (selected.length === 0 || starting) {
      return;
    }
    setStarting(true);
    setError("");
    try {
      const response = await fetch("/api/session/start", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          briefId,
          strategyChoices: selected,
        }),
      });
      if (!response.ok) {
        throw new Error("Could not start session.");
      }
      const data = (await response.json()) as {
        sessionId: string;
        opener: string;
        miscStates: Record<string, string>;
      };
      storeSessionBootstrap(data.sessionId, {
        opener: data.opener,
        miscStates: data.miscStates,
      });
      router.push(`/session/${data.sessionId}`);
    } catch (startError) {
      setError(startError instanceof Error ? startError.message : "Session start failed.");
    } finally {
      setStarting(false);
    }
  };

  return (
    <div className="mx-auto flex min-h-screen w-full max-w-3xl flex-col gap-4 p-4 md:p-6">
      <div className="rounded-2xl border border-slate-200 bg-white p-6 shadow-md">
        <p className="text-xs font-semibold uppercase tracking-widest text-slate-500">Pre-teach</p>
        <h1 className="mt-2 text-2xl font-bold text-slate-900">
          Teach {brief.persona.name} about {brief.subject}
        </h1>
      </div>

      {loading ? (
        <div className="rounded-2xl border border-slate-200 bg-white p-6 text-sm text-slate-600 shadow-sm">
          Preparing your primer...
        </div>
      ) : null}

      {!loading && payload && step === 0 ? (
        <section className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
          <h2 className="text-lg font-semibold text-slate-900">Before you teach</h2>
          <p className="mt-3 whitespace-pre-line text-sm leading-relaxed text-slate-700">
            {payload.concept_primer}
          </p>
          <button
            type="button"
            onClick={() => setStep(1)}
            className="mt-5 rounded-lg bg-slate-900 px-4 py-2 text-sm font-semibold text-white"
          >
            I get it, continue
          </button>
        </section>
      ) : null}

      {!loading && payload && step === 1 ? (
        <section className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
          <h2 className="text-lg font-semibold text-slate-900">What you&apos;re walking into</h2>
          <p className="mt-3 whitespace-pre-line text-sm leading-relaxed text-slate-700">
            {payload.misconception_preview}
          </p>
          <div className="mt-4 rounded-lg border border-indigo-200 bg-indigo-50 p-3 text-sm text-indigo-900">
            Sam will mostly reason correctly. Sometimes they&apos;ll have misconceptions. Sometimes
            they&apos;ll be confidently wrong about side details. <strong>Don&apos;t over-correct.</strong>{" "}
            <strong>Don&apos;t under-challenge.</strong>
          </div>
          <button
            type="button"
            onClick={() => setStep(2)}
            className="mt-5 rounded-lg bg-slate-900 px-4 py-2 text-sm font-semibold text-white"
          >
            Got it
          </button>
        </section>
      ) : null}

      {!loading && payload && step === 2 ? (
        <section className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
          <h2 className="text-lg font-semibold text-slate-900">Pick your approach</h2>
          <p className="mt-2 text-sm text-slate-600">Choose one or two strategy options.</p>
          <div className="mt-4 flex flex-wrap gap-2">
            {payload.strategy_options.map((option) => {
              const active = selected.includes(option);
              return (
                <button
                  key={option}
                  type="button"
                  onClick={() => toggleStrategy(option)}
                  className={`rounded-full border px-3 py-1.5 text-sm ${
                    active
                      ? "border-indigo-600 bg-indigo-600 text-white"
                      : "border-slate-300 bg-white text-slate-700"
                  }`}
                >
                  {option}
                </button>
              );
            })}
          </div>
          <button
            type="button"
            disabled={selected.length === 0 || starting}
            onClick={startSession}
            className="mt-5 rounded-lg bg-indigo-600 px-4 py-2 text-sm font-semibold text-white disabled:cursor-not-allowed disabled:bg-slate-300"
          >
            {starting ? "Starting..." : "Start session"}
          </button>
        </section>
      ) : null}

      {error ? (
        <div className="rounded-lg border border-rose-200 bg-rose-50 p-3 text-sm text-rose-900">
          {error}
        </div>
      ) : null}
    </div>
  );
}
